import{_ as a,c as i,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"高度編集：パイプラインと内部メカニズム | AI App Factory チュートリアル","description":"AI App Factory の7段階パイプライン、Sisyphus スケジューラ、権限とセキュリティメカニズム、失敗処理戦略について深く理解します。コンテキスト最適化と高度な設定テクニックを習得します。","frontmatter":{"title":"高度編集：パイプラインと内部メカニズム | AI App Factory チュートリアル","sidebarTitle":"高度編集：パイプライン","subtitle":"高度編集：パイプラインと内部メカニズム","description":"AI App Factory の7段階パイプライン、Sisyphus スケジューラ、権限とセキュリティメカニズム、失敗処理戦略について深く理解します。コンテキスト最適化と高度な設定テクニックを習得します。","tags":["パイプライン","スケジューラ","権限とセキュリティ","失敗処理"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"ja/hyz1992/agent-app-factory/advanced/index.md","filePath":"ja/hyz1992/agent-app-factory/advanced/index.md"}'),e={name:"ja/hyz1992/agent-app-factory/advanced/index.md"};function o(s,t,n,p,d,h){return l(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="高度編集-パイプラインと内部メカニズム" tabindex="-1">高度編集：パイプラインと内部メカニズム <a class="header-anchor" href="#高度編集-パイプラインと内部メカニズム" aria-label="Permalink to &quot;高度編集：パイプラインと内部メカニズム&quot;">​</a></h1><p>本セクションでは、AI App Factory の中核メカニズムと高度な機能について詳しく解説します。7段階パイプラインの詳細な仕組み、Sisyphus スケジューラのスケジューリング戦略、権限とセキュリティメカニズム、失敗処理戦略、そしてコンテキスト最適化によりトークンコストを削減する方法について学びます。</p><div class="warning custom-block"><p class="custom-block-title">前提条件</p><p>本セクションを学習する前に、以下が完了していることを確認してください：</p><ul><li><a href="./../../start/getting-started/">クイックスタート</a> と <a href="./../../start/installation/">インストール設定</a></li><li><a href="./../../start/pipeline-overview/">7段階パイプライン概要</a></li><li><a href="./../../platforms/claude-code/">プラットフォーム連携</a> 設定</li></ul></div><h2 id="セクション内容" tabindex="-1">セクション内容 <a class="header-anchor" href="#セクション内容" aria-label="Permalink to &quot;セクション内容&quot;">​</a></h2><p>本セクションには以下のトピックが含まれます：</p><h3 id="_7段階パイプライン詳解" tabindex="-1">7段階パイプライン詳解 <a class="header-anchor" href="#_7段階パイプライン詳解" aria-label="Permalink to &quot;7段階パイプライン詳解&quot;">​</a></h3><ul><li><p><strong><a href="./stage-bootstrap/">ステージ 1：Bootstrap - 構造化された製品アイデア</a></strong></p><ul><li>曖昧な製品アイデアを構造化されたドキュメントに変換する方法を学ぶ</li><li>Bootstrap Agent の入出力形式を理解する</li></ul></li><li><p><strong><a href="./stage-prd/">ステージ 2：PRD - 製品要件ドキュメントの生成</a></strong></p><ul><li>ユーザーストーリー、機能リスト、非目標を含む MVP レベルの PRD を生成する</li><li>要件分解と優先順位付けのテクニックを習得する</li></ul></li><li><p><strong><a href="./stage-ui/">ステージ 3：UI - インターフェースとプロトタイプの設計</a></strong></p><ul><li>ui-ux-pro-max スキルを使用して UI 構造とプレビュー可能なプロトタイプを設計する</li><li>インターフェース設計フローとベストプラクティスを理解する</li></ul></li><li><p><strong><a href="./stage-tech/">ステージ 4：Tech - 技術アーキテクチャの設計</a></strong></p><ul><li>最小限の実行可能な技術アーキテクチャと Prisma データモデルを設計する</li><li>技術選定とアーキテクチャ設計の原則を習得する</li></ul></li><li><p><strong><a href="./stage-code/">ステージ 5：Code - 実行可能なコードの生成</a></strong></p><ul><li>UI Schema と Tech 設計に基づいてフロントエンド・バックエンドコード、テスト、設定を生成する</li><li>コード生成フローとテンプレートシステムを理解する</li></ul></li><li><p><strong><a href="./stage-validation/">ステージ 6：Validation - コード品質の検証</a></strong></p><ul><li>依存関係のインストール、型チェック、Prisma スキーマ、コード品質を検証する</li><li>自動化された品質チェックフローを習得する</li></ul></li><li><p><strong><a href="./stage-preview/">ステージ 7：Preview - デプロイガイドの生成</a></strong></p><ul><li>完全な実行説明ドキュメントとデプロイ設定を生成する</li><li>CI/CD 統合と Git Hooks 設定を学ぶ</li></ul></li></ul><h3 id="内部メカニズム" tabindex="-1">内部メカニズム <a class="header-anchor" href="#内部メカニズム" aria-label="Permalink to &quot;内部メカニズム&quot;">​</a></h3><ul><li><p><strong><a href="./orchestrator/">Sisyphus スケジューラ詳解</a></strong></p><ul><li>スケジューラがパイプラインを調整、状態を管理、権限チェックを実行する仕組みを理解する</li><li>スケジューリング戦略とステートマシンの原理を習得する</li></ul></li><li><p><strong><a href="./context-optimization/">コンテキスト最適化：セッション分割実行</a></strong></p><ul><li><code>factory continue</code> コマンドを使用してトークンを節約する方法を学ぶ</li><li>各ステージで新しいセッションを作成するベストプラクティスを習得する</li></ul></li><li><p><strong><a href="./security-permissions/">権限とセキュリティメカニズム</a></strong></p><ul><li>能力境界マトリクス、権限超過処理、セキュリティチェックメカニズムを理解する</li><li>セキュリティ設定と権限管理を習得する</li></ul></li><li><p><strong><a href="./failure-handling/">失敗処理とロールバック</a></strong></p><ul><li>失敗の識別、再試行メカニズム、ロールバック戦略、手動介入フローを学ぶ</li><li>トラブルシューティングと復旧テクニックを習得する</li></ul></li></ul><h2 id="学習パス推奨" tabindex="-1">学習パス推奨 <a class="header-anchor" href="#学習パス推奨" aria-label="Permalink to &quot;学習パス推奨&quot;">​</a></h2><h3 id="推奨学習順序" tabindex="-1">推奨学習順序 <a class="header-anchor" href="#推奨学習順序" aria-label="Permalink to &quot;推奨学習順序&quot;">​</a></h3><ol><li><p><strong>まず7段階パイプラインを完了する</strong>（順番に）</p><ul><li>Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>各ステージには明確な入出力があり、順番に学ぶことで完全な理解が得られる</li></ul></li><li><p><strong>次にスケジューラとコンテキスト最適化を学ぶ</strong></p><ul><li>Sisyphus がこの7ステージをどう調整するかを理解する</li><li>トークンコストを最適化する方法を学ぶ</li></ul></li><li><p><strong>最後にセキュリティと失敗処理を学ぶ</strong></p><ul><li>権限境界とセキュリティメカニズムを習得する</li><li>失敗シナリオと対応戦略を理解する</li></ul></li></ol><h3 id="異なる役割の学習重点" tabindex="-1">異なる役割の学習重点 <a class="header-anchor" href="#異なる役割の学習重点" aria-label="Permalink to &quot;異なる役割の学習重点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>役割</th><th>重点学習セクション</th></tr></thead><tbody><tr><td><strong>開発者</strong></td><td>Code、Validation、Tech、Orchestrator</td></tr><tr><td><strong>プロダクトマネージャー</strong></td><td>Bootstrap、PRD、UI、Preview</td></tr><tr><td><strong>テックリード</strong></td><td>Tech、Code、Security、Failure Handling</td></tr><tr><td><strong>DevOps エンジニア</strong></td><td>Validation、Preview、Context Optimization</td></tr></tbody></table><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本セクションを完了したら、以下を続けて学ぶことができます：</p><ul><li><strong><a href="./../../faq/troubleshooting/">よくある質問とトラブルシューティング</a></strong> - 実際の使用における問題の解決</li><li><strong><a href="./../../faq/best-practices/">ベストプラクティス</a></strong> - Factory を効率的に使用するテクニックの習得</li><li><strong><a href="./../../appendix/cli-commands/">CLI コマンドリファレンス</a></strong> - 完全なコマンドリストの確認</li><li><strong><a href="./../../appendix/code-standards/">コーディング規約</a></strong> - 生成されたコードが従うべき規約の理解</li></ul><hr><p>💡 <strong>ヒント</strong>：使用中に問題が発生した場合は、まず <a href="./../../faq/troubleshooting/">よくある質問とトラブルシューティング</a> セクションをご確認ください。</p>',19)])])}const g=a(e,[["render",o]]);export{c as __pageData,g as default};
